import React from 'react'

import { SEO } from 'components/feature'
import { LayoutMain, Main } from 'components/layouts'
import { Header, NotFound, Footer } from 'containers'

const browser = typeof window !== 'undefined' && window

const NotFoundPage = () => {
  return (
    browser && (
      <LayoutMain>
        <SEO title='Page not found!' description='Sorry, the page you were looking for does not exist. (404)' />
        <Header />
        <Main role='main'>
          <NotFound />
        </Main>
        <Footer />
      </LayoutMain>
    )
  )
}

export default NotFoundPage
